      def _clean_obj(pred: str, obj: str) -> str:
          obj = obj.strip('"')
          if pred in ("language", "officialLanguage") and obj.lower().endswith(" language"):
              return obj[: -len(" language")]
          return obj

      clauses = []
      prev_subj = None
