          tmpl = templates.get(t.predicate)
          obj = _clean_obj(t.predicate, t.object)
          if tmpl:
              phrase = tmpl.format(obj=obj)
          else:
              phrase = f"{t.predicate.replace('_', ' ')} {obj}"
          if prev_subj == t.subject:
              clause = phrase
          else:
              clause = f"{t.subject} {phrase}"
          clauses.append(clause)
          prev_subj = t.subject

      sentence = ", ".join(clauses) + "."
      return sentence
